operations.query:
query {
    products(storeId: "B2B-store" currencyCode: "USD" first: 3 filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3" facet: "price.USD") {
      totalCount
      pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
      edges { cursor node { id name } }
      items { id }
      filter_facets { name label count }
      range_facets { name label ranges { count } }
      term_facets { name label terms { term count } }
    }
  }
